//www.w3.org/2000/svg",width:"5.832ex",height:"2.452ex",role:"img",focusable:"false",viewBox:"0 -833.9 2577.6 1083.9","aria-hidden":"true"},G={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},z={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.566ex"},xmlns:"http://www.w3.org/2000/svg",width:"4.618ex",height:"2.262ex",role:"img",focusable:"false",viewBox:"0 -750 2041 1000","aria-hidden":"true"};function O(q,a,$,U,K,W){return l(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1722038209000"},[a[99]||(a[99]=i('<h1 id="_15-三数之和" tabindex="-1"><a href="https://leetcode.cn/problems/3sum/description/" target="_blank" rel="noreferrer">15. 三数之和</a> <a class="header-anchor" href="#_15-三数之和" aria-label="Permalink to &quot;[15. 三数之和](https://leetcode.cn/problems/3sum/description/)&quot;">​</a></h1><p>给你一个整数数组<code>nums</code>，判断是否存在三元组<code>[nums[i], nums[j], nums[k]]</code>满足<code>i != j</code>、<code>i != k</code>且<code>j != k</code>，同时还满足<code>nums[i] + nums[j] + nums[k] == 0</code>。请</p><p>你返回所有和为<code>0</code>且不重复的三元组。</p><p><strong>注意：</strong> 答案中不可以包含重复的三元组。</p><p><strong>示例 1：</strong></p><blockquote><p><strong>输入：</strong> nums = [-1,0,1,2,-1,-4]</p><p><strong>输出：</strong>[[-1,-1,2],[-1,0,1]]</p><p><strong>解释：</strong></p><p>nums[0] + nums[1] + nums[2] = (-1) + 0 + 1 = 0 。</p><p>nums[1] + nums[2] + nums[4] = 0 + 1 + (-1) = 0 。</p><p>nums[0] + nums[3] + nums[4] = (-1) + 2 + (-1) = 0 。</p><p>不同的三元组是 [-1,0,1] 和 [-1,-1,2] 。</p><p>注意，输出的顺序和三元组的顺序并不重要。</p></blockquote><p><strong>示例 2：</strong></p><blockquote><p><strong>输入：</strong> nums = [0,1,1]</p><p><strong>输出：</strong> []</p><p><strong>解释：</strong> 唯一可能的三元组和不为 0 。</p></blockquote><p><strong>示例 3：</strong></p><blockquote><p><strong>输入：</strong> nums = [0,0,0]</p><p><strong>输出：</strong> [[0,0,0]]</p><p><strong>解释：</strong> 唯一可能的三元组和为 0 。</p></blockquote><p><strong>提示：</strong></p>',11)),s("ul",null,[s("li",null,[s("mjx-container",T,[(l(),n("svg",p,[...a